import { useEffect, useRef, useState, type ReactNode } from "react";
import { useTranslation } from "@/i18n";
import {
  fetchCumulativeVolume,
  fetchDexesPoweredCount,
  fetchMajorChainsCount,
  formatCompactUsd,
} from "@/utils/orderlyPublicStats";

type TrustMetrics = {
  dexesPowered: number | null;
  cumulativeVolume: number | null;
  supportedChains: number | null;
};

const TRUST_METRIC_FALLBACK = "--";

const FUNNEL_PAGE_BG =
  "radial-gradient(1200px 600px at 80% -10%, rgba(124,92,252,0.18), transparent 60%), radial-gradient(900px 500px at -10% 30%, rgba(232,121,249,0.1), transparent 60%), var(--bg-base)";

function formatIntegerPlus(value: number | null) {
  if (value == null) return TRUST_METRIC_FALLBACK;

  return `${new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 0,
  }).format(value)}+`;
}

async function loadTrustMetrics(): Promise<TrustMetrics> {
  const [dexesPowered, cumulativeVolume, supportedChains] =
    await Promise.allSettled([
      fetchDexesPoweredCount(),
      fetchCumulativeVolume(),
      fetchMajorChainsCount(),
    ]);

  return {
    dexesPowered:
      dexesPowered.status === "fulfilled" ? dexesPowered.value : null,
    cumulativeVolume:
      cumulativeVolume.status === "fulfilled" ? cumulativeVolume.value : null,
    supportedChains:
      supportedChains.status === "fulfilled" ? supportedChains.value : null,
  };
}

