export function FunnelPage({
  children,
  narrow = false,
}: {
  children: ReactNode;
  narrow?: boolean;
}) {
  useEffect(() => {
    const layoutScrollContainer = document.querySelector("body main");
    if (layoutScrollContainer instanceof HTMLElement) {
      layoutScrollContainer.scrollTo({ left: 0, top: 0 });
    }
    window.scrollTo({ left: 0, top: 0 });
  }, []);

  return (
    <div
      className="relative min-h-screen overflow-hidden font-body text-(--fg-primary)"
      style={{ background: FUNNEL_PAGE_BG }}
    >
      <main
        className={`mx-auto px-5 pb-24 pt-36 lg:px-7 lg:pb-24 lg:pt-36 ${
          narrow ? "max-w-[720px]" : "max-w-[1120px]"
        }`}
      >
        {children}
      </main>
    </div>
  );
}

export function ProgressSteps({ current }: { current: 1 | 2 | 3 }) {
  const { t } = useTranslation();
  const steps = [
    t("distributor.boostedApplication.progressDetails"),
    t("distributor.boostedApplication.progressQuestions"),
    t("distributor.boostedApplication.progressDone"),
  ];

  return (
    <div
      className="mb-10 flex items-center gap-3 text-[13px] text-(--fg-secondary)"
      aria-label="Progress"
    >
      {steps.map((label, index) => {
        const stepNumber = (index + 1) as 1 | 2 | 3;
        const isActive = stepNumber === current;
        const isDone = stepNumber < current;

        return (
          <div key={label} className="contents">
            <div className="flex items-center gap-2.5">
              <span
                className={`grid h-[26px] w-[26px] place-items-center rounded-full text-xs font-semibold transition-colors ${
                  isActive
                    ? "border border-transparent bg-(--fg-brand) text-white shadow-[0_0_0_4px_var(--bg-primary-subtle)]"
                    : isDone
                      ? "border border-(--line-brand) bg-(--bg-primary-subtle) text-(--fg-brand)"
                      : "border border-(--line-subtle) bg-(--bg-surface-primary) text-(--fg-secondary)"
                }`}
              >
                {isDone ? <CheckIcon /> : stepNumber}
              </span>
              <span
                className={
                  isActive ? "text-(--fg-primary)" : "text-(--fg-secondary)"
                }
              >
                {label}
              </span>
            </div>
            {stepNumber < 3 && <span className="h-px w-9 bg-(--line-subtle)" />}
          </div>
        );
      })}
    </div>
  );
}

