export function TrustStrip() {
  const { t } = useTranslation();
  const [metrics, setMetrics] = useState<TrustMetrics>({
    dexesPowered: null,
    cumulativeVolume: null,
    supportedChains: null,
  });

  useEffect(() => {
    let isCancelled = false;

    loadTrustMetrics().then(nextMetrics => {
      if (!isCancelled) {
        setMetrics(nextMetrics);
      }
    });

    return () => {
      isCancelled = true;
    };
  }, []);

  return (
    <div className="mt-12 flex flex-wrap gap-7 gap-x-10 border-t border-(--line-subtle) pt-7 text-[13px] text-(--fg-secondary)">
      <div>
        <strong className="mb-0.5 block text-[22px] font-bold tracking-[-0.02em] text-(--fg-primary)">
          {formatIntegerPlus(metrics.dexesPowered)}
        </strong>
        <span>{t("distributor.boostedApplication.dexesPowered")}</span>
      </div>
      <div>
        <strong className="mb-0.5 block text-[22px] font-bold tracking-[-0.02em] text-(--fg-primary)">
          {formatCompactUsd(metrics.cumulativeVolume)}
        </strong>
        <span>{t("distributor.boostedApplication.cumulativeVolume")}</span>
      </div>
      <div>
        <strong className="mb-0.5 block text-[22px] font-bold tracking-[-0.02em] text-(--fg-primary)">
          {formatIntegerPlus(metrics.supportedChains)}
        </strong>
        <span>{t("distributor.boostedApplication.chainsSupported")}</span>
      </div>
    </div>
  );
}

export function VideoCard({
  title,
  caption,
  duration,
  src,
  poster,
  youtubeId,
}: {
  title: string;
  caption: string;
  duration: string;
  src?: string;
  poster: string;
  youtubeId?: string;
}) {
  const { t } = useTranslation();
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const [showOverlay, setShowOverlay] = useState(true);
  const [isYouTubeActive, setIsYouTubeActive] = useState(false);
  const normalizedYouTubeId = youtubeId?.trim();
  const hasYouTube = Boolean(normalizedYouTubeId);
  const hasMp4Video = typeof src === "string" && src.trim().length > 0;
  const hasVideo = hasYouTube || hasMp4Video;
  const videoCaption = t("distributor.boostedApplication.videoCaption", {
    caption,
    duration,
  });
  const youtubeEmbedUrl = normalizedYouTubeId
    ? `https://www.youtube.com/embed/${normalizedYouTubeId}?autoplay=1&rel=0&modestbranding=1&playsinline=1`
    : null;

  const handlePlayClick = () => {
    if (!hasVideo) return;

    if (hasYouTube) {
      setIsYouTubeActive(true);
      setShowOverlay(false);
      return;
    }

    setShowOverlay(false);

    const playPromise = videoRef.current?.play();
    if (playPromise) {
      playPromise.catch(() => setShowOverlay(true));
    }
  };

  return (
    <div className="mx-auto max-w-[420px]">
      <div className="relative aspect-[9/16] overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary)">
        {hasYouTube && isYouTubeActive && youtubeEmbedUrl ? (
          <iframe
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
            allowFullScreen
            className="block h-full w-full border-0"
            loading="lazy"
            referrerPolicy="strict-origin-when-cross-origin"
            src={youtubeEmbedUrl}
            title={title}
          />
        ) : hasMp4Video ? (
          <video
            className="block h-full w-full object-cover"
            controls={!showOverlay}
            controlsList="nodownload"
            onEnded={() => setShowOverlay(true)}
            onContextMenu={event => event.preventDefault()}
            onPlay={() => setShowOverlay(false)}
            disablePictureInPicture
            playsInline
            poster={poster}
            preload="metadata"
            ref={videoRef}
            title={title}
          >
            <source src={src} type="video/mp4" />
            {t("distributor.boostedApplication.videoPlaceholder")}
          </video>
        ) : (
          <div
            aria-label={title}
            className="block h-full w-full bg-cover bg-center"
            role="img"
            style={{ backgroundImage: `url(${poster})` }}
          />
        )}
        {showOverlay && hasVideo ? (
          <button
            aria-label={title}
            className="group absolute inset-0 flex cursor-pointer flex-col items-center justify-center gap-[22px] border-0 bg-[rgba(6,6,10,0.56)] p-7 text-center text-(--fg-primary)"
            onClick={handlePlayClick}
            type="button"
          >
            <span className="flex max-w-[310px] items-center justify-center gap-2 rounded-full border border-(--line-subtle) bg-[rgba(10,10,15,0.74)] px-3.5 py-2.5 text-xs leading-[1.35] text-(--fg-primary) backdrop-blur-[10px]">
              <span className="i-mdi:clock-outline h-3.5 w-3.5" />
              <span>{videoCaption}</span>
            </span>
            <span
              className="grid h-[76px] w-[76px] place-items-center rounded-full bg-[rgba(255,255,255,0.95)] shadow-[0_10px_40px_rgba(0,0,0,0.4)] transition-transform duration-200 group-hover:scale-[1.06] group-hover:shadow-[0_12px_48px_rgba(0,0,0,0.45)]"
              aria-hidden="true"
            >
              <svg
                viewBox="0 0 24 24"
                className="ml-1 h-7 w-7"
                style={{ fill: "var(--bg-surface-primary)" }}
              >
                <path d="M8 5v14l11-7z" />
              </svg>
            </span>
          </button>
        ) : showOverlay ? (
          <div className="absolute inset-0 flex cursor-default flex-col items-center justify-center gap-[22px] border-0 p-7 text-center">
            <span className="flex max-w-[310px] items-center justify-center gap-2 rounded-full border border-(--line-subtle) bg-[rgba(10,10,15,0.74)] px-3.5 py-2.5 text-xs leading-[1.35] text-(--fg-primary) backdrop-blur-[10px]">
              <span className="i-mdi:clock-outline h-3.5 w-3.5" />
              <span>{videoCaption}</span>
            </span>
            <span className="max-w-[260px] text-[13px] leading-[1.4] text-(--fg-secondary)">
              <span className="my-2 block text-[15px] font-semibold text-(--fg-primary)">
                {title}
              </span>
              {t("distributor.boostedApplication.videoPlaceholder")}
            </span>
          </div>
        ) : null}
      </div>
    </div>
  );
}
