import { apiClient } from "@/utils/api";

const ORDERLY_DASHBOARD_API_URL =
  "https://data-api.orderly.network/orderly/api/v1/dashboard/orderly/main";
const COMPACT_USD_UNITS = [
  { value: 1_000_000_000_000, suffix: "T" },
  { value: 1_000_000_000, suffix: "B" },
  { value: 1_000_000, suffix: "M" },
  { value: 1_000, suffix: "K" },
] as const;
const METRIC_FALLBACK = "--";

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function getPositiveMetric(value: unknown) {
  const metricValue = Number(value);
  return Number.isFinite(metricValue) && metricValue > 0 ? metricValue : null;
}

export function formatCompactUsd(value: number | null | undefined) {
  if (value == null || !Number.isFinite(value) || value <= 0) {
    return METRIC_FALLBACK;
  }

  const unit = COMPACT_USD_UNITS.find(item => value >= item.value);
  if (!unit) {
    return `$${new Intl.NumberFormat("en-US", {
      maximumFractionDigits: 0,
    }).format(Math.floor(value))}+`;
  }

  const formatted = new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 0,
  }).format(Math.floor(value / unit.value));

  return `$${formatted}${unit.suffix}+`;
}

async function safeGet(endpoint: string): Promise<unknown> {
  try {
    return await apiClient({
      endpoint,
      token: null,
      showToastOnError: false,
    });
  } catch {
    return null;
  }
}

export async function fetchCumulativeVolume() {
  const payload = await safeGet("/v1/public/volume/stats");

  if (!isRecord(payload) || !isRecord(payload.data)) {
    return null;
  }

  return getPositiveMetric(payload.data.perp_volume_ltd);
}

export async function fetchLiveBuilders() {
  const payload = await safeGet(ORDERLY_DASHBOARD_API_URL);

  if (!isRecord(payload) || !Array.isArray(payload.rows)) {
    return null;
  }

  for (let index = payload.rows.length - 1; index >= 0; index -= 1) {
    const row = payload.rows[index];
    if (!isRecord(row)) continue;

    const metricValue = getPositiveMetric(row.active_builders_count);
    if (metricValue !== null) return metricValue;
  }

  return null;
}

export async function fetchDexesPoweredCount() {
  const payload = await safeGet("/v1/public/broker/name");

  if (!isRecord(payload) || !isRecord(payload.data)) {
    return null;
  }

  const rows = payload.data.rows;
  if (!Array.isArray(rows)) {
    return null;
  }

  const dexesPowered = rows.filter(row => {
    if (!isRecord(row)) return false;

    const brokerId = row.broker_id;
    return (
      typeof brokerId === "string" &&
      brokerId.trim().length > 0 &&
      brokerId !== "demo"
    );
  }).length;

  return dexesPowered > 0 ? dexesPowered : null;
}

