import { useCallback, useEffect, useState } from "react";
import { useAccount, useSignMessage } from "wagmi";
import { verifyWalletOwnership } from "@/utils/walletAuth";
import { walletGetItem, walletRemoveItem } from "@/utils/storage";

interface User {
  id: string;
  address: string;
}

export interface UseWalletAuthResult {
  user: User | null;
  token: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: () => Promise<void>;
  logout: () => void;
  validateToken: () => Promise<boolean>;
}

export function useWalletAuth(): UseWalletAuthResult {
  const { address, isConnected } = useAccount();
  const { signMessageAsync } = useSignMessage();
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const readStoredAuth = useCallback(() => {
    const storedToken = walletGetItem("auth_token");
    const storedUser = walletGetItem("auth_user");
    let parsedUser: User | null = null;
    try {
      if (storedUser) parsedUser = JSON.parse(storedUser);
    } catch {
      parsedUser = null;
    }

    const lowerAddress = address?.toLowerCase();
    const userAddress = parsedUser?.address?.toLowerCase();
    const tokenMatchesWallet =
      Boolean(storedToken) &&
      Boolean(lowerAddress) &&
      Boolean(userAddress) &&
      lowerAddress === userAddress;

    setToken(tokenMatchesWallet ? storedToken : null);
    setUser(tokenMatchesWallet ? parsedUser : null);
  }, [address]);

  useEffect(() => {
    readStoredAuth();

    const handleStorage = () => readStoredAuth();
    window.addEventListener("storage", handleStorage);
    window.addEventListener("authChanged", handleStorage);
    return () => {
      window.removeEventListener("storage", handleStorage);
      window.removeEventListener("authChanged", handleStorage);
    };
  }, [readStoredAuth]);

  useEffect(() => {
    if (!isConnected) {
      setToken(null);
      setUser(null);
    }
  }, [isConnected]);

  const login = useCallback(async () => {
    if (!address) throw new Error("No wallet connected.");
    setIsLoading(true);
    try {
      await verifyWalletOwnership(address, signMessageAsync);
      readStoredAuth();
    } finally {
      setIsLoading(false);
    }
  }, [address, signMessageAsync, readStoredAuth]);

  const logout = useCallback(() => {
    walletRemoveItem("auth_token");
    walletRemoveItem("auth_user");
    setToken(null);
    setUser(null);
  }, []);

  const validateToken = useCallback(async (): Promise<boolean> => {
    if (!token || !user?.address) return false;
    if (address && user.address.toLowerCase() !== address.toLowerCase()) {
      logout();
      return false;
    }
    return true;
  }, [token, user, address, logout]);

  return {
    user,
    token,
    isAuthenticated: !!user && !!token,
    isLoading,
    login,
    logout,
    validateToken,
  };
}
